const input = $input.first().json;
const query = input.query || input.input || input.model_type || JSON.stringify(input);

let modelType = '';
const lc = String(query).toLowerCase();
if (lc.includes('ridge')) modelType = 'ridge';
else if (lc.includes('lasso')) modelType = 'lasso';
else if (lc.includes('forest') || lc.includes('rf')) modelType = 'random_forest';
else if (lc.includes('gradient') || lc.includes('boost')) modelType = 'gradient_boosting';
else if (lc.includes('decision') || lc.includes('tree')) modelType = 'decision_tree';
else if (lc.includes('knn')) modelType = 'knn';
else if (lc.includes('best')) modelType = 'BEST';

return [{ json: { model_type: modelType, raw_query: String(query) } }];

const input = $input.first().json;
const raw = (input.stdout || '').trim();

let parsed;
try { parsed = JSON.parse(raw); } catch (e) {
  parsed = { status: 'parse_error', parse_error: e.message, raw_stdout: raw.slice(0, 1500), raw_stderr: (input.stderr || '').slice(0, 500), exit_code: input.exitCode };
}

const agentResponse = parsed.status === 'success'
  ? parsed.summary
  : `ERROR: ${parsed.error || parsed.parse_error || 'unknown'}\n${parsed.traceback || ''}`;

return [{
  json: {
    response: agentResponse,
    status: parsed.status,
    chosen_model: parsed.chosen_model,
    is_new_best: parsed.is_new_best,
    history_runs: parsed.history_runs,
    _debug: parsed
  }
}];
